URL = "http://www.cne.gob.ve/web/registro_electoral/ce.php?nacionalidad=V&cedula={cedula}"
PATTERN = r'<td align="left">(.+)<\/(td|td.+)>'

def unidecode(input_str):
    nfkd_form = unicodedata.normalize('NFKD', input_str)
    return u"".join([c for c in nfkd_form if not unicodedata.combining(c)])

def remove_html_tags(html_text):
    clean_text = re.sub('<[^<]+?>', '', html_text)
    return clean_text

def get_label_and_value(index, matches):
    return  unidecode(remove_html_tags(matches[index][0])), remove_html_tags(matches[index+1][0])

def get_range_data(initial, final, persis=False):
    data = {}
    diff = final-initial
    while diff:
        cedula = initial+diff
        r = requests.get(URL.format(cedula=cedula))
        matches = re.findall(PATTERN, r.text)
        person = {}
        for i in range(0, len(matches)-1, 2):
            label, value = get_label_and_value(i, matches)
            person[label] = value
        if person:
            data[cedula] = person
        if person or not persis:
            diff -= 1
    return data

