def xml_to_json(xml_text):
    try:
        root = ET.fromstring(xml_text)
    except:
        return {"error": "Can't find the abuser, maybe it's yourself."}
    json_data = {}
    if root.attrib:
        json_data["@attributes"] = root.attrib
    for child in root:
        if child.tag not in json_data:
            json_data[child.tag] = xml_to_json(ET.tostring(child, encoding='unicode'))
        else:
            if not isinstance(json_data[child.tag], list):
                json_data[child.tag] = [json_data[child.tag]]
            json_data[child.tag].append(xml_to_json(ET.tostring(child, encoding='unicode')))
    if root.text and root.text.strip():
        json_data = root.text.strip()
    return json_data

