const fs = require('fs');
const ImageScript = require('imagescript');

const font = fs.readFileSync(process.env.FILE_1);

const layout = new ImageScript.TextLayout({
  maxHeight: 711, maxWidth: 758,
  wrapStyle: "word", wrapHardBreaks: false,
  horizontalAlign: "middle",
});

(async () => {
const back = new ImageScript.Image(1920, 1080).fill(0x000000FF);
const front = await ImageScript.decode(fs.readFileSync(process.env.FILE_2));

const name = discord.message.referenced_message.author.username;
const avatar = await ImageScript.decode(fs.readFileSync(process.env.FILE_3));
const content = discord.message.referenced_message.content;

avatar.resize(935, 1080);
avatar.lightness(0.5);
avatar.saturation(0);
back.composite(avatar,0,0);
back.composite(front, 0,0);

const nameText = await ImageScript.Image.renderText(font, 65, "- " + name, 0x999999FF);
back.composite(nameText, front.width/1.35-nameText.width/1.35, front.height/1.2);

const contentText = await ImageScript.Image.renderText(font, 75-(parseInt(content.length)/7.5), String(content), 0xFFFFFFFF, layout);
back.composite(contentText, front.width/1.6-nameText.width/1.6, front.height/5);

const value = await back.encode();
fs.writeFileSync('./output/file.png', value);

})();
}
